  1→import crypto from 'node:crypto';
  2→import { TtlCache } from '../../utils/ttl-cache';
  3→import type { PortfolioToken } from './onchain.schemas';
  4→
  5→// ─── Config ─────────────────────────────────────────────────────────────────
  6→
  7→const OKX_API_KEY = process.env.OKX_API_KEY || '';
  8→const OKX_API_SECRET = process.env.OKX_API_SECRET || '';
  9→const OKX_API_PASSPHRASE = process.env.OKX_API_PASSPHRASE || '';
 10→const OKX_BASE_URL = 'https://web3.okx.com';
 11→const PORTFOLIO_CACHE_TTL_MS = 300_000; // 5 minutes
 12→
 13→if (!OKX_API_KEY) {
 14→    console.warn('⚠️  Missing OKX_API_KEY — OnchainOS features disabled');
 15→}
 16→
 17→// ─── Types (OKX API response shapes) ────────────────────────────────────────
 18→
 19→interface OkxTokenBalance {
 20→    symbol: string;
 21→    tokenContractAddress: string;
 22→    balance: string;
 23→    tokenPrice: string;
 24→    chainIndex: string;
 25→    logoUrl?: string;
 26→}
 27→
 28→interface OkxTotalValueResponse {
 29→    code: string;
 30→    data: Array<{ totalValue: string }>;
 31→}
 32→
 33→interface OkxAllBalancesResponse {
 34→    code: string;
 35→    data: Array<{ tokenAssets: OkxTokenBalance[] }>;
 36→}
 37→
 38→// ─── Cache ──────────────────────────────────────────────────────────────────
 39→
 40→interface PortfolioData {
 41→    totalValueUsd: string;
 42→    tokens: PortfolioToken[];
 43→}
 44→
 45→const portfolioCache = new TtlCache<PortfolioData>();
 46→
 47→// ─── Chain ID → name mapping ────────────────────────────────────────────────
 48→
 49→const CHAIN_NAMES: Record<string, string> = {
 50→    '1': 'Ethereum',
 51→    '56': 'BSC',
 52→    '8453': 'Base',
 53→    '42161': 'Arbitrum',
 54→    '137': 'Polygon',
 55→    '196': 'XLayer',
 56→    '501': 'Solana',
 57→    '10': 'Optimism',
 58→    '43114': 'Avalanche',
 59→};
 60→
 61→// ─── HMAC-SHA256 signing ────────────────────────────────────────────────────
 62→
 63→function signRequest(timestamp: string, method: string, path: string, body = ''): string {
 64→    const prehash = timestamp + method.toUpperCase() + path + body;
 65→    return crypto
 66→        .createHmac('sha256', OKX_API_SECRET)
 67→        .update(prehash)
 68→        .digest('base64');
 69→}
 70→
 71→function buildHeaders(method: string, path: string, body = ''): Record<string, string> {
 72→    const timestamp = new Date().toISOString();
 73→    return {
 74→        'OK-ACCESS-KEY': OKX_API_KEY,
 75→        'OK-ACCESS-SIGN': signRequest(timestamp, method, path, body),
 76→        'OK-ACCESS-TIMESTAMP': timestamp,
 77→        'OK-ACCESS-PASSPHRASE': OKX_API_PASSPHRASE,
 78→        'Content-Type': 'application/json',
 79→    };
 80→}
 81→
 82→// ─── OKX API helpers ────────────────────────────────────────────────────────
 83→
 84→async function okxGet<T>(path: string): Promise<T | null> {
 85→    if (!OKX_API_KEY) return null;
 86→
 87→    try {
 88→        const res = await fetch(`${OKX_BASE_URL}${path}`, {
 89→            method: 'GET',
 90→            headers: buildHeaders('GET', path),
 91→            signal: AbortSignal.timeout(5000),
 92→        });
 93→
 94→        if (!res.ok) {
 95→            console.error(`OKX API error: ${res.status} ${res.statusText} for ${path}`);
 96→            return null;
 97→        }
 98→
 99→        return await res.json() as T;
100→    } catch (err) {
101→        console.error(`OKX API request failed for ${path}:`, err);
102→        return null;
103→    }
104→}
105→
106→// ─── Public API ─────────────────────────────────────────────────────────────
107→
108→export function isOnchainEnabled(): boolean {
109→    return !!OKX_API_KEY;
110→}
111→
112→export async function getWalletPortfolio(
113→    address: string,
114→    chainIds: string,
115→): Promise<PortfolioData | null> {
116→    const cacheKey = `portfolio:${address}:${chainIds}`;
117→    const cached = portfolioCache.get(cacheKey);
118→    if (cached) return cached;
119→
120→    // Fetch total value (by-address variant — no accountId needed)
121→    const totalPath = `/api/v5/wallet/asset/total-value-by-address?address=${address}&chains=${chainIds}`;
122→    const totalRes = await okxGet<OkxTotalValueResponse>(totalPath);
123→
124→    // Fetch all token balances (by-address variant)
125→    const balancePath = `/api/v5/wallet/asset/all-token-balances-by-address?address=${address}&chains=${chainIds}`;
126→    const balanceRes = await okxGet<OkxAllBalancesResponse>(balancePath);
127→
128→    if (!totalRes?.data?.[0] || !balanceRes?.data?.[0]) return null;
129→
130→    const totalValueUsd = totalRes.data[0].totalValue || '0';
131→
132→    // Sort by USD value descending, take top 5
133→    const tokenAssets = balanceRes.data[0].tokenAssets || [];
134→    const top5 = tokenAssets
135→        .filter(t => parseFloat(t.tokenPrice) > 0 && parseFloat(t.balance) > 0)
136→        .sort((a, b) => {
137→            const aVal = parseFloat(a.balance) * parseFloat(a.tokenPrice);
138→            const bVal = parseFloat(b.balance) * parseFloat(b.tokenPrice);
139→            return bVal - aVal;
140→        })
141→        .slice(0, 5)
142→        .map((t): PortfolioToken => ({
143→            symbol: t.symbol,
144→            chainName: CHAIN_NAMES[t.chainIndex] || `Chain ${t.chainIndex}`,
145→            balance: t.balance,
146→            valueUsd: (parseFloat(t.balance) * parseFloat(t.tokenPrice)).toFixed(2),
147→            logoUrl: t.logoUrl || null,
148→        }));
149→
150→    const result: PortfolioData = { totalValueUsd, tokens: top5 };
151→    portfolioCache.set(cacheKey, result, PORTFOLIO_CACHE_TTL_MS);
152→    return result;
153→}
