132→// ─── Helpers ─────────────────────────────────────────────────────────────────
133→
134→export const NATIVE_TOKEN_ADDRESS = '0x0000000000000000000000000000000000000000';
135→
136→export function getChainById(chainId: number): ChainConfig | undefined {
137→    return Object.values(SUPPORTED_CHAINS).find(c => c.id === chainId);
138→}
139→
140→export function getTokenInfo(chainId: number, symbol: string): TokenInfo | undefined {
141→    return TOKEN_REGISTRY[chainId]?.[symbol];
142→}
143→
144→export function getTokenByAddress(chainId: number, address: string): TokenInfo | undefined {
145→    const tokens = TOKEN_REGISTRY[chainId];
146→    if (!tokens) return undefined;
147→    return Object.values(tokens).find(t => t.address.toLowerCase() === address.toLowerCase());
148→}
149→
150→export function isNativeToken(address: string): boolean {
151→    return address === NATIVE_TOKEN_ADDRESS;
152→}
153→
154→/** Chain IDs supported for escrow deposits */
155→export const ESCROW_CHAIN_IDS = [8453, 84532, 56, 97] as const;
156→export type EscrowChainId = typeof ESCROW_CHAIN_IDS[number];
157→
158→export type NetworkMode = 'testnet' | 'mainnet';
159→
160→/** Get chains filtered by network mode */
161→export function getActiveChains(mode: NetworkMode): ChainConfig[] {
162→    return Object.values(SUPPORTED_CHAINS).filter(
163→        c => mode === 'testnet' ? c.isTestnet : !c.isTestnet
164→    );
165→}
166→
167→/** Get active escrow chain IDs filtered by network mode */
168→export function getActiveEscrowChainIds(mode: NetworkMode): number[] {
169→    return ESCROW_CHAIN_IDS.filter(id => {
170→        const chain = getChainById(id);
171→        return chain && (mode === 'testnet' ? chain.isTestnet : !chain.isTestnet);
172→    });
173→}
