  1→import { FastifyInstance } from 'fastify';
  2→import { z } from 'zod';
  3→import { getDepositParams, getEscrowStatus, executeDistribute, executeRefund } from './escrow.service';
  4→import { isEscrowConfigured, escrowConfig, isChainAllowed } from './escrow.config';
  5→import { issueLlmKeysForQuest } from '../quests/llm-key-reward.service';
  6→import { getPublicClient } from './escrow.client';
  7→import { escrowPollerHealth } from './escrow.poller';
  8→// ─── Escrow Routes ───────────────────────────────────────────────────────────
  9→
 10→export async function escrowRoutes(server: FastifyInstance) {
 11→
 12→    // ── GET /escrow/supported-chains ───────────────────────────────────────────
 13→    // Returns the list of chains available in the current environment.
 14→    server.get(
 15→        '/supported-chains',
 16→        {
 17→            schema: {
 18→                tags: ['Escrow'],
 19→                summary: 'Get supported chains for the current environment',
 20→                response: {
 21→                    200: z.object({
 22→                        chains: z.array(z.object({
 23→                            id: z.number(),
 24→                            name: z.string(),
 25→                            isTestnet: z.boolean(),
 26→                        })),
 27→                        networkMode: z.enum(['testnet', 'mainnet']),
 28→                    }),
 29→                },
 30→            },
 31→        },
 32→        async () => {
 33→            const { getChainById } = await import('@clawquest/shared');
 34→            const chains = escrowConfig.activeChainIds
 35→                .map(id => getChainById(id))
 36→                .filter((c): c is NonNullable<typeof c> => !!c);
 37→            return {
 38→                chains: chains.map(c => ({ id: c.id, name: c.name, isTestnet: c.isTestnet })),
 39→                networkMode: escrowConfig.networkMode,
 40→            };
 41→        }
 42→    );
 43→
 44→    // ── GET /escrow/deposit-params/:questId ──────────────────────────────────
 45→    // Returns parameters needed by the frontend to construct deposit tx.
 46→    // Public endpoint — no auth required (sponsor needs these to deposit).
 47→    server.get(
 48→        '/deposit-params/:questId',
 49→        {
 50→            schema: {
 51→                tags: ['Escrow'],
 52→                summary: 'Get deposit parameters for a quest',
 53→                params: z.object({ questId: z.string().uuid() }),
 54→                querystring: z.object({
 55→                    chainId: z.coerce.number().optional(),
