  1→// ─── UUID ↔ bytes32 Conversion ───────────────────────────────────────────────
  2→//
  3→// Quest IDs are UUIDs in the database but bytes32 on-chain.
  4→// UUID: "007d6b1e-59a5-481d-91d9-55442ca40898"
  5→// bytes32: 0x00000000000000000000000000000000007d6b1e59a5481d91d955442ca40898
  6→//
  7→// Strategy: strip hyphens → left-pad to 64 hex chars → prefix with 0x
  8→
  9→/**
 10→ * Convert a UUID string to a bytes32 hex string for on-chain use.
 11→ * @param uuid - Standard UUID format (with or without hyphens)
 12→ * @returns bytes32 hex string prefixed with 0x
 13→ */
 14→export function uuidToBytes32(uuid: string): `0x${string}` {
 15→    const hex = uuid.replace(/-/g, '');
 16→    if (hex.length !== 32) {
 17→        throw new Error(`Invalid UUID: expected 32 hex chars after stripping hyphens, got ${hex.length}`);
 18→    }
 19→    // Left-pad with zeros to 64 hex chars (32 bytes)
 20→    return `0x${'0'.repeat(32)}${hex}` as `0x${string}`;
 21→}
 22→
 23→/**
 24→ * Convert a bytes32 hex string back to a UUID string.
 25→ * @param bytes32 - 0x-prefixed hex string (64 hex chars)
 26→ * @returns Standard UUID format with hyphens
 27→ */
 28→export function bytes32ToUuid(bytes32: string): string {
 29→    const hex = bytes32.replace(/^0x/, '');
 30→    if (hex.length !== 64) {
 31→        throw new Error(`Invalid bytes32: expected 64 hex chars, got ${hex.length}`);
 32→    }
 33→    // Take last 32 hex chars (the UUID portion)
 34→    const uuid = hex.slice(32);
 35→    return `${uuid.slice(0, 8)}-${uuid.slice(8, 12)}-${uuid.slice(12, 16)}-${uuid.slice(16, 20)}-${uuid.slice(20)}`;
 36→}
 37→
 38→// ─── Sub-QuestId for Multi-Sponsor ───────────────────────────────────────────
 39→//
 40→// Each sponsor gets a unique on-chain questId derived from the logical questId + userId.
 41→// Owner uses the original uuidToBytes32(questId). Sponsors use a keccak256 hash.
 42→// NOTE: viem is not a shared pkg dep, so we defer keccak256 to the API layer.
 43→// This function produces the concatenated hex for the caller to hash.
 44→
 45→/**
 46→ * Generate the pre-image for a sub-questId (caller must keccak256 the result).
 47→ * Returns the concatenation of questIdBytes32 + userIdBytes32.
 48→ */
 49→export function subQuestIdPreimage(questId: string, userId: string): `0x${string}` {
 50→    const questIdBytes32 = uuidToBytes32(questId);
 51→    const userIdBytes32 = uuidToBytes32(userId);
 52→    // Strip 0x prefix from second, concatenate
 53→    return `0x${questIdBytes32.slice(2)}${userIdBytes32.slice(2)}` as `0x${string}`;
 54→}
