29→/** Get viem Chain object. Falls back to defineChain() from SUPPORTED_CHAINS metadata. */
30→function getViemChain(chainId: number): Chain {
31→    const known = CHAIN_MAP[chainId];
32→    if (known) return known;
33→
34→    // Dynamic fallback: build Chain from shared SUPPORTED_CHAINS
35→    const meta = getChainById(chainId);
36→    if (meta) {
