43→            },
44→            blockExplorers: {
45→                default: { name: meta.name, url: meta.explorerUrl },
46→            },
47→            testnet: meta.isTestnet,
48→        });
49→    }
50→
51→    throw new Error(`Unsupported chainId: ${chainId} (not in viem or SUPPORTED_CHAINS)`);
52→}
