56→/** Build a viem transport for a chain using DB-sourced RPCs with fallback. */
57→function buildTransport(chainId: number) {
58→    const urls = rpcManager.getRpcUrls(chainId);
59→    if (urls.length === 0) {
60→        // Last resort: fall back to env/shared config
61→        return http(getRpcUrl(chainId));
62→    }
63→    if (urls.length === 1) {
64→        return http(urls[0]);
65→    }
66→    // Multiple RPCs: use viem fallback transport — tries each URL in order on failure
67→    return fallback(urls.map(url => http(url)));
68→}
