 10→/** Parse ESCROW_CHAIN_IDS env var (comma-separated) into number[].
 11→ *  Falls back to shared ESCROW_CHAIN_IDS constant filtered by networkMode. */
 12→function parseActiveChainIds(networkMode: NetworkMode): number[] {
 13→    const envVal = process.env.ESCROW_CHAIN_IDS;
 14→    if (envVal) {
 15→        const ids = envVal.split(',').map(s => parseInt(s.trim(), 10)).filter(n => !isNaN(n));
 16→        // Validate against SUPPORTED_CHAINS
 17→        const valid = ids.filter(id => {
 18→            const chain = getChainById(id);
 19→            if (!chain) {
 20→                console.warn(`[escrow:config] ESCROW_CHAIN_IDS contains unknown chain ${id} — skipping`);
 21→                return false;
 22→            }
 23→            return true;
 24→        });
 25→        if (valid.length === 0) {
 26→            console.warn('[escrow:config] ESCROW_CHAIN_IDS has no valid chains, falling back to shared defaults');
 27→        } else {
 28→            return valid;
 29→        }
 30→    }
 31→
 32→    // Fallback: shared constant filtered by networkMode
 33→    return ESCROW_CHAIN_IDS.filter(id => {
 34→        const chain = getChainById(id);
 35→        return chain && (networkMode === 'testnet' ? chain.isTestnet : !chain.isTestnet);
 36→    });
 37→}
 38→
 39→/** Build per-chain contract address map.
 40→ *  Priority: ESCROW_CONTRACT_<chainId> → ESCROW_CONTRACT (shared CREATE2 address) */
 41→function buildContractAddresses(activeChainIds: number[]): Record<number, `0x${string}`> {
 42→    const shared = (process.env.ESCROW_CONTRACT || '') as `0x${string}`;
 43→    const map: Record<number, `0x${string}`> = {};
 44→
 45→    for (const chainId of activeChainIds) {
 46→        const perChain = process.env[`ESCROW_CONTRACT_${chainId}`] as `0x${string}` | undefined;
 47→        if (perChain) {
 48→            map[chainId] = perChain;
 49→        } else if (shared) {
 50→            map[chainId] = shared;
 51→        }
 52→    }
 53→
 54→    return map;
 55→}
 56→
 57→/** Resolve RPC URL for a chain.
 58→ *  Priority: RPC_URL_<chainId> → legacy env names → SUPPORTED_CHAINS[].rpcUrl */
 59→function resolveRpcUrl(chainId: number): string | undefined {
 60→    // 1. Direct chain ID env var (new canonical format)
 61→    const directEnv = process.env[`RPC_URL_${chainId}`];
 62→    if (directEnv) return directEnv;
 63→
 64→    // 2. Legacy named env vars (backward compat)
 65→    const legacyMap: Record<number, string> = {
 66→        8453: 'RPC_URL_BASE',
 67→        84532: 'RPC_URL_BASE_SEPOLIA',
 68→        56: 'RPC_URL_BNB',
 69→        97: 'RPC_URL_BSC_TESTNET',
 70→    };
 71→    const legacyKey = legacyMap[chainId];
 72→    if (legacyKey && process.env[legacyKey]) return process.env[legacyKey];
 73→
 74→    // 3. SUPPORTED_CHAINS public RPC
 75→    const chain = getChainById(chainId);
 76→    return chain?.rpcUrl;
 77→}
 78→
 79→/** Build RPC URL map for all active chains */
 80→function buildRpcUrls(activeChainIds: number[]): Record<number, string> {
 81→    const map: Record<number, string> = {};
 82→    for (const chainId of activeChainIds) {
 83→        const url = resolveRpcUrl(chainId);
 84→        if (url) {
 85→            map[chainId] = url;
 86→        } else {
 87→            console.warn(`[escrow:config] No RPC URL for chain ${chainId}`);
 88→        }
 89→    }
 90→    return map;
 91→}
 92→
 93→const networkMode = (process.env.ESCROW_NETWORK_MODE || 'testnet') as NetworkMode;
 94→const activeChainIds = parseActiveChainIds(networkMode);
 95→
 96→export const escrowConfig = {
 97→    /** Active chain IDs for this environment (source of truth) */
 98→    activeChainIds,
 99→
100→    /** Per-chain escrow contract addresses */
101→    contractAddresses: buildContractAddresses(activeChainIds),
102→
103→    /** @deprecated Use contractAddresses[chainId] instead. Kept for backward compat. */
104→    contractAddress: (process.env.ESCROW_CONTRACT || '') as `0x${string}`,
105→
106→    /** Operator private key (hot wallet for distribute/refund) */
107→    operatorKey: (process.env.OPERATOR_PRIVATE_KEY || '') as `0x${string}`,
108→
109→    /** Default chain ID for the escrow (first active chain, or Base Sepolia) */
110→    defaultChainId: parseInt(process.env.ESCROW_CHAIN_ID || String(activeChainIds[0] || 84532), 10),
111→
112→    /** Network mode: 'testnet' shows only testnets, 'mainnet' shows only mainnets */
113→    networkMode,
114→
115→    /** Event polling interval in ms */
116→    pollingIntervalMs: parseInt(process.env.ESCROW_POLL_INTERVAL || '15000', 10),
117→
118→    /** Number of blocks behind chain tip to process (re-org safety buffer) */
119→    confirmationBlocks: parseInt(process.env.ESCROW_CONFIRMATION_BLOCKS || '5', 10),
120→
121→    /** RPC URLs per chain */
122→    rpcUrls: buildRpcUrls(activeChainIds),
123→} as const;
124→
125→/** Check if escrow is configured (has at least one contract address + operator key) */
126→export function isEscrowConfigured(): boolean {
127→    const hasContract = Object.keys(escrowConfig.contractAddresses).length > 0
128→        || !!escrowConfig.contractAddress;
129→    return !!(hasContract && escrowConfig.operatorKey);
130→}
131→
132→/** Get contract address for a specific chain */
133→export function getContractAddress(chainId: number): `0x${string}` {
134→    const addr = escrowConfig.contractAddresses[chainId] || escrowConfig.contractAddress;
135→    if (!addr) throw new Error(`No escrow contract configured for chainId ${chainId}`);
136→    return addr;
137→}
138→
139→/** Get RPC URL for a given chain ID */
140→export function getRpcUrl(chainId: number): string {
141→    const url = escrowConfig.rpcUrls[chainId] || resolveRpcUrl(chainId);
142→    if (!url) throw new Error(`No RPC URL configured for chainId ${chainId}`);
143→    return url;
144→}
145→
146→/** Check if a chainId is allowed in the current environment */
147→export function isChainAllowed(chainId: number): boolean {
148→    return escrowConfig.activeChainIds.includes(chainId);
149→}
150→
151→// Startup log: show active chains
152→console.log(
153→    `[escrow:config] Active chains: [${escrowConfig.activeChainIds.join(', ')}] ` +
154→    `(mode: ${escrowConfig.networkMode})`
155→);
156→
157→// Warn if defaultChainId not in active list
158→if (!isChainAllowed(escrowConfig.defaultChainId)) {
159→    console.warn(
160→        `[escrow] ESCROW_CHAIN_ID=${escrowConfig.defaultChainId} is not in active chains ` +
161→        `[${escrowConfig.activeChainIds.join(', ')}]. Update ESCROW_CHAIN_ID.`
162→    );
163→}
