  6→    defineChain,
  7→    type PublicClient,
  8→    type WalletClient,
  9→    type Chain,
 10→} from 'viem';
 11→import { privateKeyToAccount } from 'viem/accounts';
 12→import { base, baseSepolia, mainnet, bsc, bscTestnet, arbitrum, polygon } from 'viem/chains';
 13→import { getChainById } from '@clawquest/shared';
 14→import { escrowConfig, getRpcUrl } from './escrow.config';
 15→import { rpcManager } from './rpc-manager.service';
 16→
 17→// ─── Chain Mapping ───────────────────────────────────────────────────────────
 18→
 19→const CHAIN_MAP: Record<number, Chain> = {
 20→    8453: base,
 21→    84532: baseSepolia,
 22→    1: mainnet,
 23→    56: bsc,
 24→    97: bscTestnet,
 25→    42161: arbitrum,
 26→    137: polygon,
 27→};
 28→
 29→/** Get viem Chain object. Falls back to defineChain() from SUPPORTED_CHAINS metadata. */
 30→function getViemChain(chainId: number): Chain {
 31→    const known = CHAIN_MAP[chainId];
 32→    if (known) return known;
 33→
 34→    // Dynamic fallback: build Chain from shared SUPPORTED_CHAINS
 35→    const meta = getChainById(chainId);
 36→    if (meta) {
 37→        return defineChain({
 38→            id: meta.id,
 39→            name: meta.name,
 40→            nativeCurrency: meta.nativeCurrency,
 41→            rpcUrls: {
 42→                default: { http: [meta.rpcUrl] },
 43→            },
 44→            blockExplorers: {
 45→                default: { name: meta.name, url: meta.explorerUrl },
 46→            },
 47→            testnet: meta.isTestnet,
 48→        });
 49→    }
 50→
 51→    throw new Error(`Unsupported chainId: ${chainId} (not in viem or SUPPORTED_CHAINS)`);
 52→}
 53→
 54→// ─── Transport Builder ───────────────────────────────────────────────────────
 55→
 56→/** Build a viem transport for a chain using DB-sourced RPCs with fallback. */
 57→function buildTransport(chainId: number) {
 58→    const urls = rpcManager.getRpcUrls(chainId);
 59→    if (urls.length === 0) {
 60→        // Last resort: fall back to env/shared config
 61→        return http(getRpcUrl(chainId));
 62→    }
 63→    if (urls.length === 1) {
 64→        return http(urls[0]);
 65→    }
 66→    // Multiple RPCs: use viem fallback transport — tries each URL in order on failure
 67→    return fallback(urls.map(url => http(url)));
 68→}
 69→
 70→// ─── Client Caches ───────────────────────────────────────────────────────────
 71→
 72→const publicClients = new Map<number, PublicClient>();
 73→const walletClients = new Map<number, WalletClient>();
 74→
 75→/** Clear cached clients (call after rpcManager reloads at runtime). */
 76→export function invalidateClientCache(): void {
 77→    publicClients.clear();
 78→    walletClients.clear();
 79→}
 80→
 81→// ─── Public Client (read-only) ──────────────────────────────────────────────
 82→
 83→export function getPublicClient(chainId: number): PublicClient {
 84→    let client = publicClients.get(chainId);
 85→    if (!client) {
 86→        const chain = getViemChain(chainId);
 87→        client = createPublicClient({
 88→            chain,
 89→            transport: buildTransport(chainId),
 90→        }) as PublicClient;
 91→        publicClients.set(chainId, client);
 92→    }
 93→    return client;
 94→}
 95→
 96→// ─── Wallet Client (operator — for distribute/refund) ────────────────────────
 97→
 98→export function getOperatorWalletClient(chainId: number): WalletClient {
 99→    let client = walletClients.get(chainId);
100→    if (!client) {
101→        if (!escrowConfig.operatorKey) {
102→            throw new Error('OPERATOR_PRIVATE_KEY not configured');
103→        }
104→        const chain = getViemChain(chainId);
105→        const account = privateKeyToAccount(escrowConfig.operatorKey);
106→        client = createWalletClient({
107→            account,
108→            chain,
109→            transport: buildTransport(chainId),
110→        });
111→        walletClients.set(chainId, client);
112→    }
113→    return client;
114→}
115→
116→/** Get operator wallet address */
117→export function getOperatorAddress(): `0x${string}` {
118→    if (!escrowConfig.operatorKey) {
119→        throw new Error('OPERATOR_PRIVATE_KEY not configured');
120→    }
121→    return privateKeyToAccount(escrowConfig.operatorKey).address;
122→}
